def apply_dynamic_filters(
    search_results: list[SearchResult],
    filter_specs: dict[str, dict[str, Any]],
    filter_logic: str = "AND"
) -> list[SearchResult]:
    # Convert filter specifications into a list of individual filters
    individual_filters = []
    for field, condition in filter_specs.items():
        for operator, value in condition.items():
            individual_filters.append({
                "field": field,
                "operator": operator,
                "value": value
            })

    # Create MetadataFilterEngine with the specified logic and filters
    filter_engine = MetadataFilterEngine(
        filters=individual_filters,
        logic=filter_logic
    )

    # Apply the filter engine to each SearchResult
    filtered_results = []
    for result in search_results:
        if filter_engine.evaluate(result.metadata):
            filtered_results.append(result)

    return filtered_results

