            return compute_embeddings(
                chunks=texts_tuple,
                model_name=model_name,
                mode=mode,
                use_server=False,
                is_build=False,
                provider_options=kwargs.get("provider_options")
            )

        # Use lru_cache with a custom key function
        @lru_cache(maxsize=128)
        def cached_compute(**kwargs) -> np.ndarray:
            return compute_func(**kwargs)

        # Call the cached function with provider_options if available
        provider_options_arg = embedding_options or {}
        result = cached_compute(provider_options=provider_options_arg)
    else:
        # Compute embeddings without caching
        result = compute_embeddings(
            texts,
            model_name,
            mode,
            use_server=False,
            is_build=False,
            provider_options=embedding_options
        )

    return np.asarray(result)

