    for group_value, results in grouped.items():
        group_stats = {}
        for stat_name, func in aggregation_funcs.items():
            try:
                group_stats[stat_name] = func(results)
            except Exception:
                # If aggregation fails, skip this statistic
                continue
        aggregated[group_value] = group_stats

