def aggregate_search_results(
    search_results: List[SearchResult],
    group_by_field: str,
    aggregation_funcs: Optional[dict[str, Callable]] = None
) -> dict[str, dict[str, Any]]:
    groups = defaultdict(
        lambda: {
            'count': 0,
            'sum_score': 0.0,
            'max_score': -float('inf'),
            'min_score': float('inf'),
            'data': {}
        }
    )

    # Define default aggregation functions
    default_aggs = {
        'count': lambda g: g['count'],
        'average_score': lambda g: g['sum_score'] / g['count'],
        'max_score': lambda g: g['max_score'],
        'min_score': lambda g: g['min_score'],
    }

    # Merge user-provided aggregation functions, overriding defaults
    if aggregation_funcs is not None:
        for field, func in aggregation_funcs.items():
            default_aggs[field] = func

    # Process each SearchResult
    for result in search_results:
        group_key = result.metadata.get(group_by_field, 'unknown')
        group = groups[group_key]
        group['count'] += 1
        group['sum_score'] += result.score
        group['max_score'] = max(group['max_score'], result.score)
        group['min_score'] = min(group['min_score'], result.score)

        # Collect data for custom aggregation functions
        if aggregation_funcs is not None:
            for field, func in aggregation_funcs.items():
                if field != group_by_field:
                    value = result.metadata.get(field)
                    if value is not None:
                        if field not in group['data']:
                            group['data'][field] = []
                        group['data'][field].append(value)

    # Build the result dictionary
    result_dict = {}
    for group_key, group in groups.items():
        group_stats = {}
        for agg_name, agg_func in default_aggs.items():
            if agg_name in ('count', 'average_score', 'max_score', 'min_score'):
                # Compute using group data
                if agg_name == 'count':
                    group_stats[agg_name] = group['count']
                elif agg_name == 'average_score':
                    group_stats[agg_name] = group['sum_score'] / group['count']
                elif agg_name == 'max_score':
                    group_stats[agg_name] = group['max_score']
                elif agg_name == 'min_score':
                    group_stats[agg_name] = group['min_score']
            else:
                # Apply custom aggregation function
                field_values = group['data'].get(agg_name, [])
                if field_values:
                    group_stats[agg_name] = agg_func(field_values)
        result_dict[group_key] = group_stats

    return result_dict

