def verify_index_integrity(index_path: str) -> dict[str, Any]:
    meta_path_str = f"{index_path}.meta.json"
    if not Path(meta_path_str).exists():
        raise FileNotFoundError("Index metadata file not found")

    with open(meta_path_str) as f:
        meta = json.load(f)

    backend_name = meta.get("backend_name")
    expected_passages = meta.get("passage_count")
    passages_source = meta.get("passages_source")

    if not Path(passages_source).exists():
        return {
            "is_valid": False,
            "passage_count": 0,
            "metadata_file_exists": True,
            "errors": ["Passages source file is missing"]
        }

    passage_manager = PassageManager()
    try:
        passage_manager.load(passages_source)
    except Exception as e:
        return {
            "is_valid": False,
            "passage_count": 0,
            "metadata_file_exists": True,
            "errors": [str(e)]
        }

    actual_passage_count = len(passage_manager.passages)
    if actual_passage_count != expected_passages:
        return {
            "is_valid": False,
            "passage_count": actual_passage_count,
            "metadata_file_exists": True,
            "errors": [f"Passage count mismatch: expected {expected_passages}, got {actual_passage_count}"]
        }

    index_file = f"{index_path}.index"
    if not Path(index_file).exists():
        return {
            "is_valid": False,
            "passage_count": actual_passage_count,
            "metadata_file_exists": True,
            "errors": [f"Index file not found at {index_file}"]
        }

    errors = []
    is_valid = True

    try:
        backend_module = __import__(backend_name, fromlist=["LeannBackend"])
        backend_class = getattr(backend_module, "LeannBackend")
        searcher = LeannSearcher(index_file=index_file, backend_module=backend_class)
        # Perform a dummy search to validate the index
        try:
            searcher.search("dummy", top_k=1)
        except Exception as e:
            errors.append(str(e))
            is_valid = False
    except ImportError:
        errors.append(f"Backend module '{backend_name}' not found")
        is_valid = False
    except AttributeError:
        errors.append(f"Backend class not found in module '{backend_name}'")
        is_valid = False
    except Exception as e:
        errors.append(str(e))
        is_valid = False

    return {
        "is_valid": is_valid,
        "passage_count": actual_passage_count,
        "metadata_file_exists": True,
        "errors": errors
    }

