def get_index_statistics(index_path: str) -> dict[str, Any]:
    try:
        pm = PassageManager(index_path)
        meta = pm.meta
        total_passages = meta.get('total_passages', len(pm.get_passage_ids()))

        # Collect all unique field names across all passages
        all_fields = set()
        for passage_id in pm.get_passage_ids():
            passage_meta = pm.get_passage_meta(passage_id)
            all_fields.update(passage_meta.keys())

        # Count occurrences of each field value
