        for passage_id in pm.get_passage_ids():
            passage_meta = pm.get_passage_meta(passage_id)
            for field in all_fields:
                value = passage_meta.get(field)
                if value is not None:
                    field_value_counts[field][value] += 1

        return {
            "total_passages": total_passages,
            "metadata_fields": sorted(all_fields),
            "field_value_counts": {k: dict(v) for k, v in field_value_counts.items()}
