        raise FileNotFoundError("Index metadata file not found")

def analyze_index_coverage(index_path: str, required_fields: List[str]) -> dict[str, Any]:
    try:
        pm = PassageManager(index_path)
        meta = pm.meta
        total = len(pm.get_passage_ids())

        all_covered = 0
        field_coverages = defaultdict(int)
        present_fields = set()

        for passage_id in pm.get_passage_ids():
            passage_meta = pm.get_passage_meta(passage_id)
            missing = [field for field in required_fields if field not in passage_meta]
            if not missing:
                all_covered += 1
            for field in required_fields:
                if field in passage_meta:
                    field_coverages[field] += 1
            present_fields.update(passage_meta.keys())

        coverage_percentage = (all_covered / total) * 100 if total > 0 else 0
        field_coverage = {field: (count / total) * 100 for field, count in field_coverages.items()}
        missing_in_all = [field for field in required_fields if field not in present_fields]

        return {
            "coverage_percentage": coverage_percentage,
            "field_coverage": field_coverage,
            "missing_fields": missing_in_all
        }
    except FileNotFoundError:
        raise FileNotFoundError("Index metadata file not found")

